import { GoogleGenAI, Type } from "@google/genai";
import { GEMINI_PROMPT, QUESTIONS, VitalCode } from '../constants';
import type { Answers, Report, Score } from '../types';

export const getVitalCodeReport = async (answers: Answers): Promise<Report> => {
  // 1. Calculate scores in the frontend to ensure accuracy
  const scores: Score[] = Object.values(VitalCode).map(code => {
    const codeQuestions = QUESTIONS.filter(q => q.code === code);
    const puntos = codeQuestions.reduce((sum, q) => sum + (answers[q.id] || 0), 0);
    return { codigo: code, puntos };
  });

  // Sort scores to identify top ones
  const sortedScores = [...scores].sort((a, b) => b.puntos - a.puntos);

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      resultado: {
        type: Type.OBJECT,
        properties: {
          principal: { type: Type.STRING },
          secundarios: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          puntuaciones: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                codigo: { type: Type.STRING },
                puntos: { type: Type.NUMBER },
              },
              required: ['codigo', 'puntos'],
            },
          },
          informe: {
            type: Type.OBJECT,
            properties: {
              perfil: { type: Type.STRING },
              descripcion: { type: Type.STRING },
              fortalezas: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
              retos: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
              recomendaciones: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
            },
            required: ['perfil', 'descripcion', 'fortalezas', 'retos', 'recomendaciones'],
          },
        },
        required: ['principal', 'secundarios', 'puntuaciones', 'informe'],
      },
    },
    required: ['resultado'],
  };

  try {
    const fullPrompt = `${GEMINI_PROMPT}\n${JSON.stringify({ puntuaciones_calculadas: scores })}`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: fullPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.7,
      },
    });

    const text = response.text?.trim();
    if (!text) throw new Error("Empty response from AI");

    const parsedJson = JSON.parse(text);

    // Safety check: ensure scores are the ones we calculated if AI hallucinated them
    if (parsedJson.resultado) {
        parsedJson.resultado.puntuaciones = scores;
    }

    return parsedJson as Report;

  } catch (error) {
    console.error("Error calling Gemini API:", error);
    throw new Error("No se pudo generar el informe. Verifica tu conexión o intenta de nuevo.");
  }
};

import React, { useState, useRef } from 'react';
import type { Report, Score } from '../types';

// A simple bar chart component for scores
const ScoresChart: React.FC<{ scores: Score[] }> = ({ scores }) => {
  const maxScore = 20; // 5 questions * 4 points max
  const sortedScores = [...scores].sort((a, b) => b.puntos - a.puntos);

  return (
    <div className="space-y-3">
      {sortedScores.map(({ codigo, puntos }) => (
        <div key={codigo} className="flex items-center">
          <span className="w-28 text-sm font-medium text-beige-lunar/90 flex-shrink-0">{codigo}</span>
          <div className="w-full bg-azul-humo/50 rounded-full h-5 ml-2">
            <div
              className="bg-oro-profundo h-5 rounded-full text-xs font-medium text-azul-humo flex items-center justify-center px-2 transition-all duration-1000 ease-out"
              style={{ width: `${(puntos / maxScore) * 100}%`, minWidth: '2rem' }}
            >
              {puntos}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

// Share Modal Component
const ShareModal: React.FC<{ report: Report; onClose: () => void }> = ({ report, onClose }) => {
  const [copyButtonText, setCopyButtonText] = useState('Copiar enlace');

  const { principal, informe } = report.resultado;
  const shareUrl = window.location.href;
  const shareText = `¡Descubrí mi Código Vital: ${informe.perfil}! Mi código principal es ${principal}. Descubre el tuyo también en este test.`;
  const shareTextWithUrl = `${shareText} ${shareUrl}`;

  const encodedShareText = encodeURIComponent(shareText);
  const encodedShareTextWithUrl = encodeURIComponent(shareTextWithUrl);
  const encodedUrl = encodeURIComponent(shareUrl);
  const encodedTitle = encodeURIComponent(`Mi Perfil: ${informe.perfil}`);

  const shareOptions = [
    { name: 'WhatsApp', url: `https://api.whatsapp.com/send?text=${encodedShareTextWithUrl}` },
    { name: 'X (Twitter)', url: `https://twitter.com/intent/tweet?url=${encodedUrl}&text=${encodedShareText}` },
    { name: 'LinkedIn', url: `https://www.linkedin.com/shareArticle?mini=true&url=${encodedUrl}&title=${encodedTitle}&summary=${encodedShareText}` },
    { name: 'Email', url: `mailto:?subject=${encodedTitle}&body=${encodedShareTextWithUrl}` },
  ];

  const handleCopyLink = () => {
    navigator.clipboard.writeText(shareUrl).then(() => {
      setCopyButtonText('¡Enlace copiado!');
      setTimeout(() => setCopyButtonText('Copiar enlace'), 2000);
    });
  };

  return (
    <div className="fixed inset-0 bg-azul-humo bg-opacity-80 flex items-center justify-center z-50 animate-fade-in" onClick={onClose}>
      <div className="bg-gris-carbon rounded-2xl shadow-2xl p-6 w-full max-w-sm text-beige-lunar border border-oro-profundo/30" onClick={(e) => e.stopPropagation()}>
        <h3 className="text-xl font-bold text-center mb-6">Compartir Resultado</h3>
        <div className="grid grid-cols-1 gap-3">
          {shareOptions.map(option => (
            <a key={option.name} href={option.url} target="_blank" rel="noopener noreferrer" className="block w-full text-center px-4 py-3 bg-azul-humo font-semibold rounded-lg hover:bg-oro-profundo hover:text-azul-humo transition-colors border border-oro-profundo/20">
              {option.name}
            </a>
          ))}
          <button onClick={handleCopyLink} className="w-full px-4 py-3 bg-azul-humo font-semibold rounded-lg hover:bg-oro-profundo hover:text-azul-humo transition-colors border border-oro-profundo/20">
            {copyButtonText}
          </button>
        </div>
        <button onClick={onClose} className="mt-6 w-full text-center px-4 py-2 bg-oro-profundo text-azul-humo font-semibold rounded-lg hover:bg-beige-lunar hover:text-azul-humo transition-colors">
          Cerrar
        </button>
      </div>
    </div>
  );
};


interface ResultsScreenProps {
  report: Report | null;
  error: string | null;
  onRestart: () => void;
  userEmail: string;
}

const ResultsScreen: React.FC<ResultsScreenProps> = ({ report, error, onRestart, userEmail }) => {
  const [showShareModal, setShowShareModal] = useState(false);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
  const resultsRef = useRef<HTMLDivElement>(null);

  const downloadPdf = async () => {
    if (!resultsRef.current || !report) return;

    setIsGeneratingPdf(true);
    try {
      const { jsPDF } = (window as any).jspdf;
      const html2canvas = (window as any).html2canvas;

      const canvas = await html2canvas(resultsRef.current, {
        scale: 2,
        useCORS: true,
        backgroundColor: '#2F3135',
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const imgProps = pdf.getImageProperties(imgData);
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Informe_Codigos_Vitales_${report.resultado.informe.perfil.replace(/\s+/g, '_')}.pdf`);
    } catch (err) {
      console.error("PDF Generation error:", err);
      alert("No se pudo generar el PDF. Por favor, intenta de nuevo.");
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  if (error) {
    return (
      <div className="text-center p-8 bg-azul-humo text-beige-lunar rounded-2xl shadow-2xl border border-red-500/50 animate-fade-in">
