        <p className="text-lg text-beige-lunar/90 mb-8">{error}</p>
        <button
          onClick={() => window.location.reload()}
          className="px-8 py-3 bg-oro-profundo text-azul-humo font-bold rounded-full shadow-lg hover:bg-beige-lunar hover:text-azul-humo transform hover:scale-105 transition-all duration-300 ease-in-out"
        >
          Recargar Página
        </button>
      </div>
    );
  }

  if (!report) {
    return (
        <div className="text-center p-8 bg-azul-humo text-beige-lunar rounded-2xl shadow-2xl border border-oro-profundo/50">
          <p className="text-lg">No se ha podido cargar el informe. Por favor, inténtalo de nuevo.</p>
           <button
            onClick={onRestart}
            className="mt-6 px-8 py-3 bg-oro-profundo text-azul-humo font-bold rounded-full shadow-lg hover:bg-beige-lunar hover:text-azul-humo transform hover:scale-105 transition-all duration-300 ease-in-out"
          >
            Reiniciar Test
          </button>
        </div>
    );
  }

  const { resultado } = report;
  const { principal, secundarios, puntuaciones, informe } = resultado;

  return (
    <>
      <div ref={resultsRef} className="p-4 sm:p-10 bg-azul-humo text-beige-lunar rounded-2xl shadow-2xl border border-oro-profundo/50 animate-fade-in">
        <div className="text-center mb-10">
          <span className="text-oro-profundo font-bold tracking-widest uppercase text-sm mb-2 block">Tu Destino Revelado</span>
          <h1 className="text-5xl md:text-6xl font-bold mb-4 text-white leading-tight">
            {informe.perfil}
          </h1>
          <div className="h-1 w-24 bg-oro-profundo mx-auto mb-6"></div>
          <p className="text-2xl text-beige-lunar">
            Código Principal: <span className="font-bold text-oro-profundo">{principal}</span>
          </p>
          <p className="text-lg text-beige-lunar/70 mt-1 italic">
            Alquimia Vital: {secundarios.join(' + ')}
          </p>
        </div>

        <div className="bg-gris-carbon/20 p-8 rounded-2xl mb-10 border border-oro-profundo/10">
          <div className="prose prose-invert max-w-none">
             {informe.descripcion.split('\n').map((para, i) => (
               <p key={i} className="text-lg text-beige-lunar/90 leading-relaxed mb-4 last:mb-0">
                 {para}
               </p>
             ))}
          </div>
        </div>

        <div className="grid md:grid-cols-2 gap-8 mb-10">
          <div className="bg-gris-carbon/30 p-8 rounded-2xl border-l-4 border-oro-profundo">
              <h3 className="text-2xl font-bold text-oro-profundo mb-6 flex items-center">
                <span className="mr-2">✨</span> Tus Dones
              </h3>
              <ul className="space-y-3">
                  {informe.fortalezas.map((item, i) => (
