import { GoogleGenAI, Type } from "@google/genai";
import { GEMINI_PROMPT, QUESTIONS } from '../constants';
import { VitalCode, type Answers, type Report, type Score } from '../types';

export const getVitalCodeReport = async (answers: Answers): Promise<Report> => {
  // 1. Calcular puntuaciones en frontend para precisión matemática absoluta
  const scores: Score[] = Object.values(VitalCode).map(code => {
    const codeQuestions = QUESTIONS.filter(q => q.code === code);
    const puntos = codeQuestions.reduce((sum, q) => sum + (answers[q.id] || 0), 0);
    return { codigo: code, puntos };
  });

  // Ordenar para identificar los top
  const sortedScores = [...scores].sort((a, b) => b.puntos - a.puntos);
  const principalCandidate = sortedScores[0].codigo;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      resultado: {
        type: Type.OBJECT,
        properties: {
          principal: { type: Type.STRING },
          secundarios: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          informe: {
            type: Type.OBJECT,
            properties: {
              perfil: { type: Type.STRING },
              descripcion: { type: Type.STRING },
              fortalezas: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
              retos: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
              recomendaciones: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
            },
            required: ['perfil', 'descripcion', 'fortalezas', 'retos', 'recomendaciones'],
          },
        },
        required: ['principal', 'secundarios', 'informe'],
      },
    },
    required: ['resultado'],
  };

  try {
    const contextPrompt = `
      CONTEXTO DE PUNTUACIONES REALES:
      ${JSON.stringify(scores)}

      El código con mayor puntuación es: ${principalCandidate}.

      INSTRUCCIÓN ADICIONAL:
      Asegúrate de que la 'descripcion' tenga al menos 3 párrafos extensos y sea muy inspiradora.
      No inventes puntuaciones, usa las proporcionadas.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview", // Usamos Pro para máxima fiabilidad en lógica compleja
      contents: GEMINI_PROMPT + "\n" + contextPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.8,
      },
    });

    const text = response.text;
    if (!text) throw new Error("La IA no devolvió contenido.");

    const parsed = JSON.parse(text);

    // Validaciones de seguridad y limpieza
    if (!parsed.resultado) throw new Error("Formato de respuesta inválido.");

    // Asegurar que las puntuaciones son las reales del frontend
    parsed.resultado.puntuaciones = scores;

    // Garantizar que 'principal' sea un VitalCode válido
    if (!Object.values(VitalCode).includes(parsed.resultado.principal as VitalCode)) {
      parsed.resultado.principal = principalCandidate;
    }

    return parsed as Report;

  } catch (error) {
    console.error("Error crítico en GeminiService:", error);
    throw error;
  }
};

