import { GoogleGenAI, Type } from "@google/genai";
import { GEMINI_PROMPT, QUESTIONS } from '../constants';
import { VitalCode, type Answers, type Report, type Score } from '../types';

export const getVitalCodeReport = async (answers: Answers): Promise<Report> => {
  // 1. Cálculo de puntuaciones en el cliente para precisión matemática
  const scores: Score[] = Object.values(VitalCode).map(code => {
    const codeQuestions = QUESTIONS.filter(q => q.code === code);
    const puntos = codeQuestions.reduce((sum, q) => sum + (answers[q.id] || 0), 0);
    return { codigo: code, puntos };
  });

  // Identificar el código dominante para guiar a la IA
  const sortedScores = [...scores].sort((a, b) => b.puntos - a.puntos);
  const principalCandidate = sortedScores[0].codigo;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Definición estricta del esquema de respuesta
  const responseSchema = {
    type: Type.OBJECT,
    properties: {
      resultado: {
        type: Type.OBJECT,
        properties: {
          principal: { type: Type.STRING },
          secundarios: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
          },
          informe: {
            type: Type.OBJECT,
            properties: {
              perfil: { type: Type.STRING },
              descripcion: { type: Type.STRING },
              fortalezas: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
              retos: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
              recomendaciones: {
                type: Type.ARRAY,
                items: { type: Type.STRING },
              },
            },
            required: ['perfil', 'descripcion', 'fortalezas', 'retos', 'recomendaciones'],
          },
        },
        required: ['principal', 'secundarios', 'informe'],
      },
    },
    required: ['resultado'],
  };

  try {
    const finalPrompt = `
      ${GEMINI_PROMPT}

      DATOS REALES DEL USUARIO:
      Puntuaciones: ${JSON.stringify(scores)}
      Código Ganador: ${principalCandidate}

      POR FAVOR: Genera un informe literario, profundo y místico basado estrictamente en estos datos.
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: finalPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.8,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No se recibió respuesta del oráculo digital.");

    const parsed = JSON.parse(text);

    // Inyectamos los scores calculados por el frontend para asegurar veracidad
    if (parsed.resultado) {
      parsed.resultado.puntuaciones = scores;
    }

    return parsed as Report;

  } catch (error) {
    console.error("Error en el servicio de generación:", error);
    throw new Error("La conexión con el plano intuitivo se ha interrumpido. Por favor, intenta de nuevo.");
  }
};

